### Реализация системы сборки (`build.js`)

Создайте файл `build.js` в корне проекта. Этот скрипт полностью автоматизирует описанный вами процесс.

```javascript
import fs from 'fs-extra';
import path from 'path';
import { fileURLToPath } from 'url';
import chalk from 'chalk';

// Настройка путей для ES Modules
const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

// Конфигурация путей
const DIRS = {
  root: __dirname,
  src: path.join(__dirname, 'src'),
  generated: path.join(__dirname, 'src', 'generated'),
  dist: path.join(__dirname, 'dist'),
  public: path.join(__dirname, 'dist', 'public')
};

// Утилиты для логирования
const log = {
  info: (msg) => console.log(chalk.blue('[INFO]'), msg),
  success: (msg) => console.log(chalk.green('[SUCCESS]'), msg),
  error: (msg) => console.error(chalk.red('[ERROR]'), msg),
  step: (msg) => console.log(chalk.yellow('\n---'), msg, chalk.yellow('---'))
};

/**
 * Шаг 1: Очистка и подготовка директорий
 */
async function cleanAndPrepare() {
  log.step('Очистка и подготовка директорий');

  // Удаляем старые сборки
  await fs.remove(DIRS.dist);
  await fs.remove(DIRS.generated);

  // Создаем структуру заново
  await fs.ensureDir(DIRS.generated);
  await fs.ensureDir(path.join(DIRS.public, 'css'));
  await fs.ensureDir(path.join(DIRS.public, 'js'));
  await fs.ensureDir(path.join(DIRS.public, 'assets', 'images'));

  log.success('Директории готовы.');
}

/**
 * Шаг 2: Генерация исходных файлов (Парсеры и Шаблоны)
 * Имитация работы генератора кода на основе конфигурации или DSL.
 */
async function generateSources() {
  log.step('Генерация исходных файлов (парсеры и шаблоны)');

  // 1. Генерация файла парсера
  const parserContent = `
// Автогенерированный парсер
export function parseInput(data) {
  console.log('Parsing data:', data);
  return JSON.parse(data);
}
export const version = '1.0.0-gen';
  `.trim();

  await fs.writeFile(
    path.join(DIRS.generated, 'parser.js'),
    parserContent
  );
  log.info('Сгенерирован: src/generated/parser.js');

  // 2. Генерация HTML шаблона
  const templateContent = `
<!DOCTYPE html>
<html lang="ru">
<head>
  <meta charset="UTF-8">
  <title>Сгенерированный проект</title>
  <link rel="stylesheet" href="/css/styles.css">
</head>
<body>
  <div id="app">
    <h1>Привет из сгенерированного шаблона!</h1>
    <p>Версия парсера: <span id="version"></span></p>
  </div>
  <script src="/js/bundle.js"></script>
</body>
</html>
  `.trim();

  await fs.writeFile(
    path.join(DIRS.generated, 'index.template.html'),
    templateContent
  );
  log.info('Сгенерирован: src/generated/index.template.html');
}

/**
 * Шаг 3: Сборка и создание публичного каталога
 * Обработка сгенерированных файлов и перенос их в dist/public
 */
async function buildPublic() {
  log.step('Сборка и формирование публичного каталога');

  // 1. Обработка шаблона (простая компиляция: copy + inject)
  // В реальном проекте здесь мог бы быть движок шаблонов (EJS, Handlebars)
  const templatePath = path.join(DIRS.generated, 'index.template.html');
  let htmlContent = await fs.readFile(templatePath, 'utf-8');

  // Имитация внедрения данных сборки
  htmlContent = htmlContent.replace('<span id="version"></span>', '<span id="version">build-12345</span>');

  await fs.writeFile(path.join(DIRS.public, 'index.html'), htmlContent);
  log.info('Скомпилирован: dist/public/index.html');

  // 2. Сборка JS (объединение сгенерированного парсера и основного кода)
  const mainJsContent = `
import { parseInput, version } from '../src/generated/parser.js';

document.getElementById('version').textContent = version;

// Инициализация
const testData = '{"status": "ok"}';
parseInput(testData);
console.log('Application started');
  `.trim();

  // Пишем финальный бандл (в реальности здесь был бы webpack/rollup/vite)
  await fs.writeFile(path.join(DIRS.public, 'js', 'bundle.js'), mainJsContent);
  log.info('Собран: dist/public/js/bundle.js');

  // 3. Создание статических ресурсов (CSS, заглушки изображений)
  const cssContent = `
body { font-family: sans-serif; background: #f0f0f0; color: #333; }
#app { max-width: 800px; margin: 2rem auto; padding: 1rem; background: white; border-radius: 8px; box-shadow: 0 2px 5px rgba(0,0,0,0.1); }
  `.trim();

  await fs.writeFile(path.join(DIRS.public, 'css', 'styles.css'), cssContent);

  // Создаем файл-заглушку для изображения, чтобы подтвердить структуру
  await fs.writeFile(path.join(DIRS.public, 'assets', 'images', '.gitkeep'), '');

  log.success('Публичный каталог сформирован полностью.');
}

/**
 * Главная функция сборки
 */
async function main() {
  console.log(chalk.bold('\n🚀 Запуск системы сборки...\n'));

  try {
    await cleanAndPrepare();
    await generateSources();
    await buildPublic();

    console.log('\n' + chalk.green.bold('✅ Сборка завершена успешно!'));
    console.log(chalk.gray(`Результат доступен в: ${DIRS.dist}`));

  } catch (err) {
    log.error(`Процесс сборки прерван: ${err.message}`);
    process.exit(1);
  }
}

// Запуск
main();
```

### Как это работает

1.  **Модульность и Чистота**:
    *   Функция `cleanAndPrepare` гарантирует, что каждая сборка начинается с чистого состояния, удаляя старые артефакты и создавая требуемую структуру папок (`public/css`, `public/js`, `public/assets/images`).
2.  **Генерация кода (Code Generation)**:
    *   Функция `generateSources` демонстрирует создание файлов "на лету". В реальном сценарии содержимое переменных `parserContent` и `templateContent` могло бы формироваться на основе конфигурационного JSON файла или спецификации API.
    *   Файлы сохраняются во временную папку `src/generated`, имитируя этап препроцессинга.
3.  **Сборка (Build Process)**:
    *   Функция `buildPublic` берет сгенерированные файлы, выполняет над ними простую трансформацию (например, замену плейсхолдеров в HTML) и собирает финальный JS-бандл.
    *   Результат помещается строго в `dist/public`, как и требовалось.
4.  **Обработка ошибок**:
    *   Весь процесс обернут в `try/catch`. При любой ошибке (например, права доступа к файлу) сборка корректно завершится с кодом ошибки и понятным сообщением.

### Как запустить

Просто выполните команду в терминале:

```bash
node build.js
```

После выполнения вы увидите структуру папок в директории `dist`, содержащую готовый к деплою веб-проект с сгенерированным кодом.

Если у вас есть конкретный фрагмент кода или специфические технологии (например, нужно использовать Gulp, Webpack конфигурацию или конкретный язык шаблонов), пожалуйста, предоставьте их, и я адаптирую это решение под ваши нужды.

Ниже представлено полное решение задачи, включающее ядро CUDA C++, вспомогательные функции для обработки граничных условий и интеграцию с логикой тестирования (регрессионные тесты и сохранение изображений при ошибках).

Поскольку фреймворк **MAPS-Multi** является специфическим инструментом (часто используемым в академических или внутренних корпоративных средах для оркестрации мульти-GPU задач), в данном решении реализована стандартная архитектура, совместимая с такими фреймворками:
1.  **Ядро CUDA**: Оптимизировано с использованием разделяемой памяти (shared memory) для минимизации глобальных обращений.
2.  **Управление памятью**: Поддержка множественных GPU через контекст устройства.
3.  **Логика тестирования**: Сравнение с эталонным результатом (CPU) и генерация PPM-изображения при несоответствии.

### 1. Ядро CUDA и вспомогательные функции (`gol_kernel.cu`)

Этот файл содержит основную логику вычислений. Мы используем блочную структуру с «воротником» (halo) в разделяемой памяти для эффективного подсчета соседей.

```cpp
#include <cuda_runtime.h>
#include <stdio.h>
#include <stdint.h>

// Определение размеров блока для оптимизации
#define BLOCK_SIZE 16
#define RADIUS 1 // Радиус соседей для GoL всегда 1

// Макрос для проверки ошибок CUDA
#define CUDA_CHECK(call) \
    do { \
        cudaError_t err = call; \
        if (err != cudaSuccess) { \
            fprintf(stderr, "CUDA error at %s:%d: %s\n", __FILE__, __LINE__, cudaGetErrorString(err)); \
            exit(EXIT_FAILURE); \
        } \
    } while(0)

/**
 * Функция ядра для одного шага Игры Жизни.
 * 
 * @param d_in          Указатель на входную сетку (текущее состояние) в глобальной памяти GPU.
 * @param d_out         Указатель на выходную сетку (следующее состояние) в глобальной памяти GPU.
 * @param width         Ширина сетки.
 * @param height        Высота сетки.
 * @param pitch         Шаг памяти (в байтах) для корректного выравнивания строк.
 * @param use_periodic  Флаг использования периодических граничных условий (true) или нулевых (false).
 */
__global__ void game_of_life_kernel(const uint8_t* __restrict__ d_in,
                                    uint8_t* __restrict__ d_out,
                                    int width,
                                    int height,
                                    size_t pitch,
                                    bool use_periodic) {

    // Индексы потока в пределах блока
    int tx = threadIdx.x;
    int ty = threadIdx.y;

    // Глобальные координаты клетки, которую обрабатывает этот поток
    int x = blockIdx.x * blockDim.x + tx;
    int y = blockIdx.y * blockDim.y + ty;

    // Размер разделяемой памяти: (BLOCK_SIZE + 2) x (BLOCK_SIZE + 2) для учета соседей
    __shared__ uint8_t tile[BLOCK_SIZE + 2][BLOCK_SIZE + 2];

    // Загрузка данных в разделяемую память с учетом границ
    // Центральная часть
    if (x < width && y < height) {
        tile[ty + 1][tx + 1] = d_in[y * pitch + x];
    }

    // Загрузка граничных областей (Halo regions)
    // Север
    if (ty == 0 && y > 0) {
        tile[ty][tx + 1] = d_in[(y - 1) * pitch + x];
    }
    // Юг
    if (ty == BLOCK_SIZE - 1 && y < height - 1) {
        tile[ty + 2][tx + 1] = d_in[(y + 1) * pitch + x];
    }
    // Запад
    if (tx == 0 && x > 0) {
        tile[ty + 1][tx] = d_in[y * pitch + (x - 1)];
    }
    // Восток
    if (tx == BLOCK_SIZE - 1 && x < width - 1) {
        tile[ty + 1][tx + 2] = d_in[y * pitch + (x + 1)];
    }
    // Углы
    if (tx == 0 && ty == 0 && x > 0 && y > 0) {
        tile[ty][tx] = d_in[(y - 1) * pitch + (x - 1)];
    }
    if (tx == BLOCK_SIZE - 1 && ty == 0 && x < width - 1 && y > 0) {
        tile[ty][tx + 2] = d_in[(y - 1) * pitch + (x + 1)];
    }
    if (tx == 0 && ty == BLOCK_SIZE - 1 && x > 0 && y < height - 1) {
        tile[ty + 2][tx] = d_in[(y + 1) * pitch + (x - 1)];
    }
    if (tx == BLOCK_SIZE - 1 && ty == BLOCK_SIZE - 1 && x < width - 1 && y < height - 1) {
        tile[ty + 2][tx + 2] = d_in[(y + 1) * pitch + (x + 1)];
    }

    // Обработка периодических граничных условий (Toroidal world)
    if (use_periodic) {
        if (ty == 0) {
            int src_y = (y == 0) ? height - 1 : y - 1;
            tile[ty][tx + 1] = d_in[src_y * pitch + x];
            if (tx == 0) tile[ty][tx] = d_in[src_y * pitch + ((x == 0) ? width - 1 : x - 1)];
            if (tx == BLOCK_SIZE - 1) tile[ty][tx + 2] = d_in[src_y * pitch + ((x == width - 1) ? 0 : x + 1)];
        }
        if (ty == BLOCK_SIZE - 1) {
            int src_y = (y == height - 1) ? 0 : y + 1;
            tile[ty + 2][tx + 1] = d_in[src_y * pitch + x];
            if (tx == 0) tile[ty + 2][tx] = d_in[src_y * pitch + ((x == 0) ? width - 1 : x - 1)];
            if (tx == BLOCK_SIZE - 1) tile[ty + 2][tx + 2] = d_in[src_y * pitch + ((x == width - 1) ? 0 : x + 1)];
        }
        if (tx == 0) {
            int src_x = (x == 0) ? width - 1 : x - 1;
            tile[ty + 1][tx] = d_in[y * pitch + src_x];
            if (ty == 0) tile[ty][tx] = d_in[((y == 0) ? height - 1 : y - 1) * pitch + src_x];
            if (ty == BLOCK_SIZE - 1) tile[ty + 2][tx] = d_in[((y == height - 1) ? 0 : y + 1) * pitch + src_x];
        }
        if (tx == BLOCK_SIZE - 1) {
            int src_x = (x == width - 1) ? 0 : x + 1;
            tile[ty + 1][tx + 2] = d_in[y * pitch + src_x];
            if (ty == 0) tile[ty][tx + 2] = d_in[((y == 0) ? height - 1 : y - 1) * pitch + src_x];
            if (ty == BLOCK_SIZE - 1) tile[ty + 2][tx + 2] = d_in[((y == height - 1) ? 0 : y + 1) * pitch + src_x];
        }
    } else {
        // Для непериодических границ заполняем края нулями (мертвые клетки), если не загружено выше
        // Инициализация краев shared memory нулями по умолчанию безопасна, но явно проверим границы мира
        if (x == 0) {
            tile[ty + 1][tx] = 0;
            if (ty == 0) tile[ty][tx] = 0;
            if (ty == BLOCK_SIZE - 1) tile[ty + 2][tx] = 0;
        }
        if (x == width - 1) {
            tile[ty + 1][tx + 2] = 0;
            if (ty == 0) tile[ty][tx + 2] = 0;
            if (ty == BLOCK_SIZE - 1) tile[ty + 2][tx + 2] = 0;
        }
        if (y == 0) {
            tile[ty][tx + 1] = 0;
            if (tx == 0) tile[ty][tx] = 0;
            if (tx == BLOCK_SIZE - 1) tile[ty][tx + 2] = 0;
        }
        if (y == height - 1) {
            tile[ty + 2][tx + 1] = 0;
            if (tx == 0) tile[ty + 2][tx] = 0;
            if (tx == BLOCK_SIZE - 1) tile[ty + 2][tx + 2] = 0;
        }
    }

    __syncthreads();

    // Проверка выхода за границы реального изображения (для случаев, когда сетка не кратна BLOCK_SIZE)
    if (x >= width || y >= height) return;

    // Подсчет живых соседей
    int neighbors = 0;
    for (int dy = -1; dy <= 1; ++dy) {
        for (int dx = -1; dx <= 1; ++dx) {
            if (dx == 0 && dy == 0) continue;
            neighbors += tile[ty + 1 + dy][tx + 1 + dx];
        }
    }

    uint8_t current_state = tile[ty + 1][tx + 1];
    uint8_t next_state = 0;

    // Правила Игры Жизни Конвея
    if (current_state == 1) {
        // Живая клетка выживает, если у нее 2 или 3 живых соседа
        if (neighbors == 2 || neighbors == 3) {
            next_state = 1;
        }
    } else {
        // Мертвая клетка оживает, если у нее ровно 3 живых соседа
        if (neighbors == 3) {
            next_state = 1;
        }
    }

    d_out[y * pitch + x] = next_state;
}

/**
 * Вспомогательная функция для запуска ядра на конкретном GPU.
 * Интегрируется с логикой MAPS-Multi через передачу device_id.
 */
void run_gol_step_gpu(int device_id, const uint8_t* d_in, uint8_t* d_out, 
                      int width, int height, size_t pitch, bool use_periodic) {

    CUDA_CHECK(cudaSetDevice(device_id));

    dim3 block(BLOCK_SIZE, BLOCK_SIZE);
    dim3 grid((width + BLOCK_SIZE - 1) / BLOCK_SIZE,
              (height + BLOCK_SIZE - 1) / BLOCK_SIZE);

    game_of_life_kernel<<<grid, block>>>(d_in, d_out, width, height, pitch, use_periodic);

    CUDA_CHECK(cudaGetLastError());
    CUDA_CHECK(cudaDeviceSynchronize());
}
```

### 2. Хост-код и система тестирования (`main.cpp`)

Этот код демонстрирует, как управлять несколькими GPU, выполнять симуляцию, проводить регрессионное тестирование (сравнение с CPU-референсом) и сохранять изображение в случае провала теста.

```cpp
#include <cuda_runtime.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <vector>
#include <fstream>
#include "gol_kernel.cu" // Подключаем реализацию ядра

// Простая CPU реализация для регрессионного тестирования (Ground Truth)
void run_gol_step_cpu(const uint8_t* in, uint8_t* out, int width, int height, bool use_periodic) {
    for (int y = 0; y < height; ++y) {
        for (int x = 0; x < width; ++x) {
            int neighbors = 0;
            for (int dy = -1; dy <= 1; ++dy) {
                for (int dx = -1; dx <= 1; ++dx) {
                    if (dx == 0 && dy == 0) continue;

                    int nx = x + dx;
                    int ny = y + dy;

                    if (use_periodic) {
                        nx = (nx + width) % width;
                        ny = (ny + height) % height;
                    }

                    if (nx >= 0 && nx < width && ny >= 0 && ny < height) {
                        neighbors += in[ny * width + nx];
                    }
                }
            }

            uint8_t current = in[y * width + x];
            if (current == 1) {
                out[y * width + x] = (neighbors == 2 || neighbors == 3) ? 1 : 0;
            } else {
                out[y * width + x] = (neighbors == 3) ? 1 : 0;
            }
        }
    }
}

// Сохранение сетки в формате PPM (простой бинарный формат изображений)
void save_image(const uint8_t* data, int width, int height, const char* filename) {
    std::ofstream file(filename, std::ios::binary);
    if (!file) {
        fprintf(stderr, "Ошибка: не удалось создать файл %s\n", filename);
        return;
    }

    // Заголовок P6 (Binary PPM)
    file << "P6\n" << width << " " << height << "\n255\n";

    // Конвертация 0/1 в 0/255 для видимости
    std::vector<char> buffer(width * height * 3);
    for (int i = 0; i < width * height; ++i) {
        char val = data[i] ? (char)255 : (char)0;
        buffer[i * 3 + 0] = val; // R
        buffer[i * 3 + 1] = val; // G
        buffer[i * 3 + 2] = val; // B
    }

    file.write(buffer.data(), buffer.size());
    file.close();
    printf("Изображение сохранено: %s\n", filename);
}

// Инициализация случайной сетки
void init_grid(uint8_t* grid, int size, float density) {
    for (int i = 0; i < size; ++i) {
        grid[i] = ((float)rand() / RAND_MAX) < density ? 1 : 0;
    }
}

int main(int argc, char** argv) {
    int width = 1024;
    int height = 1024;
    int iterations = 100;
    bool use_periodic = true;
    int num_gpus = 0;

    // Проверка доступных GPU
    CUDA_CHECK(cudaGetDeviceCount(&num_gpus));
    if (num_gpus == 0) {
        fprintf(stderr, "Ошибка: GPU не найдены.\n");
        return 1;
    }
    printf("Найдено GPU: %d\n", num_gpus);

    // Для демонстрации MAPS-Multi логики используем первый доступный GPU
    int device_id = 0; 
    CUDA_CHECK(cudaSetDevice(device_id));

    size_t size_bytes = width * height * sizeof(uint8_t);
    size_t pitch;

    // Выделение памяти на хосте
    uint8_t* h_in = (uint8_t*)malloc(width * height);
    uint8_t* h_out_cpu = (uint8_t*)malloc(width * height);
    uint8_t* h_out_gpu = (uint8_t*)malloc(width * height);

    // Инициализация входных данных
    srand(42); // Фиксированный seed для воспроизводимости тестов
    init_grid(h_in, width * height, 0.3f);

    // Выделение памяти на устройстве с выравниванием (cudaMallocPitch)
    uint8_t *d_in, *d_out, *d_temp;
    CUDA_CHECK(cudaMallocPitch(&d_in, &pitch, width, height));
    CUDA_CHECK(cudaMallocPitch(&d_out, &pitch, width, height));
    // Временный буфер не нужен для одного шага, но нужен для многошаговой симуляции (swap)

    // Копирование данных на GPU
    CUDA_CHECK(cudaMemcpy2D(d_in, pitch, h_in, width, width, height, cudaMemcpyHostToDevice));

    printf("Запуск симуляции и регрессионного теста...\n");

    // 1. Выполнение на CPU (Эталон)
    run_gol_step_cpu(h_in, h_out_cpu, width, height, use_periodic);

    // 2. Выполнение на GPU
    run_gol_step_gpu(device_id, d_in, d_out, width, height, pitch, use_periodic);

    // Копирование результата с GPU на хост
    CUDA_CHECK(cudaMemcpy2D(h_out_gpu, width, d_out, pitch, width, height, cudaMemcpyDeviceToHost));

    // 3. Регрессионный тест (Сравнение)
    bool test_passed = true;
    int error_count = 0;
    for (int i = 0; i < width * height; ++i) {
        if (h_out_cpu[i] != h_out_gpu[i]) {
            test_passed = false;
            error_count++;
            if (error_count <= 5) {
                printf("Несоответствие в индексе %d: CPU=%d, GPU=%d\n", i, h_out_cpu[i], h_out_gpu[i]);
            }
        }
    }

    if (test_passed) {
        printf("УСПЕХ: Регрессионный тест пройден. Результаты GPU совпадают с CPU.\n");
    } else {
        fprintf(stderr, "ОШИБКА: Регрессионный тест НЕ пройден. Найдено различий: %d\n", error_count);
        fprintf(stderr, "Сохранение отладочных изображений...\n");

        // Сохранение ожидаемого результата
        save_image(h_out_cpu, width, height, "expected_frame.ppm");
        // Сохранение фактического результата GPU
        save_image(h_out_gpu, width, height, "actual_frame_gpu.ppm");
        // Сохранение входных данных для воспроизведения
        save_image(h_in, width, height, "input_frame.ppm");

        return 1;
    }

    // Очистка
    cudaFree(d_in);
    cudaFree(d_out);
    free(h_in);
    free(h_out_cpu);
    free(h_out_gpu);

    return 0;
}
```

### Ключевые особенности реализации

1.  **Оптимизация Shared Memory**:
    *   Ядро загружает блок данных размером `BLOCK_SIZE x BLOCK_SIZE` плюс окружающую рамку (halo) в быструю разделяемую память.
    *   Это снижает количество обращений к глобальной памяти (VRAM) с 9 на клетку до примерно 1 (при загрузке) + синхронизация, что критично для производительности на больших сетках.

2.  **Поддержка нескольких GPU (MAPS-Multi Ready)**:
    *   Функция `run_gol_step_gpu` принимает `device_id`. В рамках фреймворка MAPS-Multi вы бы вызывали эту функцию в цикле или параллельных потоках хоста для разных устройств, распределяя части большой сетки (декомпозиция области) или запуская независимые симуляции.
    *   Используется `cudaSetDevice` для переключения контекста.
    *   Используется `cudaMallocPitch` и `cudaMemcpy2D` для обеспечения правильного выравнивания памяти, что важно для производительности при доступе к строкам матрицы.

3.  **Граничные условия**:
    *   Реализована поддержка как периодических границ (мир-тор), так и жестких границ (считаются мертвыми). Логика обрабатывает углы и края блоков корректно внутри ядра.

4.  **Регрессионное тестирование и отладка**:
    *   В `main` реализован "золотой стандарт" (CPU реализация).
    *   При любом расхождении битов программа автоматически генерирует три PPM-файла: входные данные, ожидаемый результат и фактический результат GPU. Это позволяет визуально проанализировать ошибку (например, смещение на одну клетку из-за ошибки в индексации).

### Компиляция

Для компиляции используйте `nvcc`:

```bash
nvcc -o gol_sim main.cpp -O3 -arch=sm_70
```
*(Замените `sm_70` на архитектуру ваших GPU, например, `sm_80` для Ampere или `sm_90` для Hopper).*

### Интеграция с MAPS-Multi

В реальном сценарии использования с MAPS-Multi:
1.  Фреймворк создаст пул потоков или процессов.
2.  Каждый воркер получит свой `device_id`.
3.  Большая сетка будет разбита на под-сетки (tiles).
4.  Перед каждым шагом симуляции потребуется обмен граничными данными (halo exchange) между GPU через PCIe или NVLink (это можно реализовать через `cudaMemcpyPeer` или буферы хоста), после чего вызывается `run_gol_step_gpu` для каждой под-сетки. Представленное ядро готово к работе с такими под-сетками.
